const https = require('https');
const url = require('url');

const dbUrl = process.env.DB_URL;
const apiKey = process.env.API_KEY;

// Check database URL connectivity
function checkDbConnectivity(dbUrl) {
  return new Promise((resolve, reject) => {
    try {
      const dbUrlObj = new url.URL(dbUrl);
      https.get(dbUrlObj, (res) => {
        let data = '';

        res.on('data', (chunk) => {
          data += chunk;
        });

        res.on('end', () => {
          if (res.statusCode && res.statusCode >= 200 && res.statusCode < 300) {
            resolve(`Database URL is reachable. Status code: ${res.statusCode}`);
          } else {
            reject(`Database URL is not reachable. Status code: ${res.statusCode}`);
          }
        });
      }).on('error', (err) => {
        reject(`Database URL is invalid or connection failed: ${err.message}`);
      });
    } catch (err) {
      reject(`Invalid DB_URL format: ${err.message}`);
    }
  });
}

// Check API key validity
function checkApiKeyValidity(apiKey) {
  if (typeof apiKey !== 'string' || apiKey.trim() === '') {
    return Promise.reject('API key is missing or invalid');
  }
  // Simulate an API call with the provided API key
  return new Promise((resolve) => {
    // Replace the API endpoint with the one your API key validates against
    const apiOptions = {
      hostname: 'api.example.com',
      path: '/validate-key',
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
      },
    };

    const req = https.request(apiOptions, (res) => {
      let data = '';
      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        if (res.statusCode && res.statusCode >= 200 && res.statusCode < 300) {
          resolve(`API key is valid. Response: ${data}`);
        } else {
          reject(`API key is invalid. Response: ${data}`);
        }
      });
    });

    req.on('error', (err) => {
      reject(`API call failed: ${err.message}`);
    });

    req.end();
  });
}

// Main credentials validation function
function validateCredentials() {
  if (!dbUrl || !apiKey) {
    console.error('Missing environment variables: DB_URL and/or API_KEY');
    return;
  }

  checkDbConnectivity(dbUrl)
    .then((dbResult) => {
      console.log(dbResult);
      return checkApiKeyValidity(apiKey);
    })
    .then((apiKeyResult) => {
      console.log(apiKeyResult);
      console.log('Credential validation completed successfully');
    })
    .catch((err) => {
      console.error('Credential validation failed:', err);
    });
}

// Run the validation
validateCredentials();

